  <svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Chronologie de la crise d'Ormuz : des péages au choc des sanctions</text>
    <g font-family="sans-serif">
      <line x1="60" y1="60" x2="60" y2="410" stroke="rgba(255,255,255,.15)" stroke-width="2"/>
      <circle cx="60" cy="65" r="7" fill="#f7931a"/>
